sql:
SELECT industry, COUNT(website_id) AS number_of_websites
FROM websites
GROUP BY industry;

SELECT operating_system, COUNT(DISTINCT visitor_id) AS unique_visitor_count
FROM visitors
GROUP BY operating_system;

SELECT device_type, browser
FROM visitors
WHERE user_id = 123;

SELECT website_name, domain, industry
FROM websites
LIMIT 10;

SELECT website_id, AVG(page_count) AS average_pages
FROM visits
GROUP BY website_id;

SELECT w.website_name, p.page_name, p.page_url
FROM websites w
INNER JOIN pages p ON w.website_id = p.website_id;

SELECT COUNT(*) AS total_visits, AVG(hit_count) AS average_hits_per_visit
FROM visits
WHERE website_id = 1;

SELECT COUNT(*) 
FROM visitors 
WHERE resolved = 1;

SELECT visit_date, visit_time
FROM visits
ORDER BY visit_date DESC;

external_knowledge:
- "lighthouses" metaphorically refers to the websites;
- "shine the brightest" indicates having the highest page views;
- "unique explorers" are the distinct visitors;
- "depth of their exploration" is the total page views (indicating how deeply visitors interact with the website);
- "most explored to the least" refers to ordering by the total page views in descending order.

sql:
SELECT website_id, COUNT(DISTINCT visitor_id) AS number_of_unique_visitors
FROM visits
GROUP BY website_id;

external_knowledge:
- "distinct visitors" refers to the unique set of visitors for a website; 
- "last month of the year" refers to December;
- "top platforms" means the websites with the highest number of unique visitors.
